:root {
  --bg-board: #1a1a2e;
  --bg-header: #16213e;
  --bg-table-head: #0f3460;
  --bg-active: #1e3a5f;
  --bg-footer: #16213e;
  --text-primary: #e8e0d0;
  --text-secondary: #9a9080;
  --text-dim: #5a5568;
  --text-brand: #f5c842;
  --border-subtle: #2a2a4a;
  --border-active: #f5c842;
  --badge-ontime-bg: #1a4731;
  --badge-ontime-text: #4cde8a;
  --badge-delayed-bg: #4a2010;
  --badge-delayed-text: #f87c3a;
  --badge-departed-bg: #2a2a3a;
  --badge-departed-text: #7a7a9a;
  --clock-bg: #0f3460;
  --platform-text: #a0c4ff;
}

.timetable {
  width: 520px;
  background: var(--bg-board);
  border-radius: 10px;
  overflow: hidden;
  border: 1px solid var(--border-subtle);
}

.board-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: var(--bg-header);
  padding: 12px 16px;
  border-bottom: 2px solid var(--border-active);
}

.header-left {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.station-label {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 3px;
  color: var(--text-brand);
}

.station-name {
  font-size: 20px;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: 0.5px;
}

.clock-badge {
  display: flex;
  flex-direction: column;
  align-items: center;
  background: var(--clock-bg);
  border-radius: 6px;
  padding: 6px 12px;
  gap: 1px;
}

.clock-time {
  font-size: 22px;
  font-weight: 700;
  color: var(--text-brand);
  line-height: 1;
}

.clock-date {
  font-size: 10px;
  color: var(--text-secondary);
  letter-spacing: 0.5px;
}

.table-head {
  display: grid;
  grid-template-columns: 70px 1fr 80px 90px;
  padding: 7px 16px;
  background: var(--bg-table-head);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 2px;
  color: var(--text-secondary);
}

.train-row {
  display: grid;
  grid-template-columns: 70px 1fr 80px 90px;
  padding: 10px 16px;
  align-items: center;
  border-bottom: 1px solid var(--border-subtle);
}

.active-row {
  background: var(--bg-active);
  border-left: 3px solid var(--border-active);
  padding-left: 13px;
}

.time {
  font-size: 15px;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: 0.5px;
}

.departed .time {
  color: var(--text-dim);
}

.destination {
  font-size: 14px;
  font-weight: 500;
  color: var(--text-primary);
}

.departed .destination {
  color: var(--text-dim);
}

.platform {
  font-size: 13px;
  font-weight: 600;
  color: var(--platform-text);
}

.departed .platform {
  color: var(--text-dim);
}

.status-badge {
  display: inline-block;
  font-size: 11px;
  font-weight: 700;
  padding: 3px 8px;
  border-radius: 4px;
  letter-spacing: 0.3px;
  width: fit-content;
}

.ontime-badge {
  background: var(--badge-ontime-bg);
  color: var(--badge-ontime-text);
}

.delayed-badge {
  background: var(--badge-delayed-bg);
  color: var(--badge-delayed-text);
}

.departed-badge {
  background: var(--badge-departed-bg);
  color: var(--badge-departed-text);
}

.board-footer {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: var(--bg-footer);
  padding: 8px 16px;
}

.footer-note {
  font-size: 11px;
  color: var(--badge-delayed-text);
}

.footer-brand {
  font-size: 13px;
  font-weight: 800;
  letter-spacing: 3px;
  color: var(--text-brand);
}
